styles:
.write-spot {
  border: 1px solid gray;
  border-radius: 0.25rem;
  padding: 0.3rem;
  background-color: var(--color-shadow);
}
@font-face {
  font-family: "AnekLatin";
  src: url("https://s3.sa-east-1.amazonaws.com/zenerp.app.br/assets/fonts/AnekLatin.ttf") format("truetype");
  font-weight: normal;
  font-style: normal;
}
html,
body {
  margin: 0;
  padding: 0;
}

.report-wrapper {
  --border-radius: 0.3em;
  --color-border: rgba(0, 0, 0, 0.1);
  --color-shadow: rgba(0, 0, 0, 0.1);
  --gap: 0.5rem;
  --padding: 0.35rem;
  box-sizing: border-box;
  font-family: "AnekLatin", "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  font-size: 11pt;
}
.report-wrapper dl {
  display: block;
  margin: 0;
  padding: 0;
}
@media screen {
  .report-wrapper {
    min-height: 100vh;
    padding: 1rem;
    background-color: lightgray;
  }
}
.report-wrapper .report-container {
  position: relative;
  box-sizing: border-box;
  page-break-after: always;
  break-after: page;
}
@media screen {
  .report-wrapper .report-container {
    margin-bottom: 1rem;
    padding: 2mm;
    background-color: white;
  }
}
.report-wrapper .report-container .stamp {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-45deg);
  font-size: 300%;
  opacity: 0.3;
  color: red;
}
.report-wrapper .report-container > header {
  display: flex;
  flex-direction: column;
  gap: var(--gap);
  border-bottom: 3px solid #000;
  padding-bottom: 1rem;
  margin-bottom: 1rem;
}
.report-wrapper .report-container > header .brand {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
}
.report-wrapper .report-container > header h1 {
  margin: 0;
  font-size: 20pt;
}
.report-wrapper .report-container > header > dl,
.report-wrapper .report-container > header section.parameters {
  display: flex;
  flex-wrap: wrap;
  gap: var(--gap);
  margin: 0;
}
.report-wrapper .report-container > header > dl div,
.report-wrapper .report-container > header > dl dl,
.report-wrapper .report-container > header section.parameters div,
.report-wrapper .report-container > header section.parameters dl {
  display: flex;
  flex-direction: column;
  flex: 1;
  border: 1px solid var(--color-border);
  border-radius: var(--border-radius);
  padding: var(--padding);
  min-width: 4cm;
}
.report-wrapper .report-container > header > dl div dt,
.report-wrapper .report-container > header > dl dl dt,
.report-wrapper .report-container > header section.parameters div dt,
.report-wrapper .report-container > header section.parameters dl dt {
  font-size: 8pt;
  color: gray;
  text-transform: uppercase;
  font-weight: bold;
}
.report-wrapper .report-container > header > dl div dd,
.report-wrapper .report-container > header > dl dl dd,
.report-wrapper .report-container > header section.parameters div dd,
.report-wrapper .report-container > header section.parameters dl dd {
  margin: 0;
}
.report-wrapper .report-container > main .kpi-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1rem;
  margin-bottom: 2rem;
}
.report-wrapper .report-container > main .kpi-grid dl {
  border: 1px solid var(--color-border);
  padding: 1rem;
  background: #fdfdfd;
  display: flex;
  justify-content: space-between;
}
.report-wrapper .report-container > main .kpi-grid dl dt {
  font-size: 9pt;
  color: gray;
}
.report-wrapper .report-container > main .kpi-grid dl dd {
  margin: 0;
  font-size: 16pt;
  font-weight: bold;
}
.report-wrapper .report-container > main .kpi-grid dl .kpi-trend {
  font-size: 8pt;
  align-self: flex-end;
}
.report-wrapper .report-container > main section {
  margin-top: 1.5rem;
}
.report-wrapper .report-container > main section section {
  padding-left: 1rem;
}
.report-wrapper .report-container > main section > header {
  font-weight: bold;
  border-bottom: 1px solid var(--color-border);
  margin-bottom: 0.5rem;
}
.report-wrapper .report-container > main section > footer {
  font-size: 9pt;
  font-style: italic;
  color: gray;
  padding-top: 5px;
}
.report-wrapper .report-container > main .content table:not(.custom) {
  table-layout: fixed;
  width: 100%;
  border-collapse: separate;
  border-spacing: var(--padding) 0;
}
.report-wrapper .report-container > main .content table:not(.custom) th {
  text-align: left;
}
.report-wrapper .report-container > main .content table:not(.custom) td {
  overflow-wrap: break-word;
}
.report-wrapper .report-container > footer {
  margin-top: 4rem;
  border-top: 2px solid #000;
  padding-top: 1rem;
}
.report-wrapper .report-container > footer .signature-block {
  display: flex;
  justify-content: space-between;
  margin-top: 2rem;
}
.report-wrapper .report-container > footer dl {
  display: flex;
  flex-wrap: wrap;
  gap: var(--gap);
  margin: 0;
}
.report-wrapper .report-container > footer dl div,
.report-wrapper .report-container > footer dl dl {
  display: flex;
  flex-direction: column;
  flex: 1;
  border: 1px solid var(--color-border);
  border-radius: var(--border-radius);
  padding: var(--padding);
  min-width: 4cm;
}
.report-wrapper .report-container > footer dl div dt,
.report-wrapper .report-container > footer dl dl dt {
  font-size: 8pt;
  color: gray;
  text-transform: uppercase;
  font-weight: bold;
}
.report-wrapper .report-container > footer dl div dd,
.report-wrapper .report-container > footer dl dl dd {
  margin: 0;
}
.report-wrapper .flex {
  display: flex;
}
.report-wrapper .flex.h {
  flex-direction: row;
}
.report-wrapper .flex.v {
  flex-direction: column;
}
.report-wrapper .flex.align-center {
  align-items: center;
}
.report-wrapper .flex.justify-center {
  justify-content: center;
}
.report-wrapper .flex.justify-space-around {
  justify-content: space-around;
}
.report-wrapper .flex.justify-space-between {
  justify-content: space-between;
}
.report-wrapper .flex.gap {
  gap: 0.5rem;
}
.report-wrapper .flex .flex-1 {
  flex: 1;
}
.report-wrapper .grid {
  display: grid;
}
.report-wrapper .text-center {
  text-align: center;
}
.report-wrapper .text-right {
  text-align: right !important;
}
.report-wrapper .date {
  font-variant-numeric: tabular-nums;
}
.report-wrapper .digits {
  font-variant-numeric: tabular-nums;
}
.report-wrapper .number {
  font-variant-numeric: tabular-nums;
  text-align: right !important;
}
.report-wrapper .number.positive,
.report-wrapper .number .positive {
  color: #4a89bd;
}
.report-wrapper .number.negative,
.report-wrapper .number .negative {
  color: #d66d67;
}
.report-wrapper .text-success {
  color: green;
}
.report-wrapper .text-danger {
  color: red;
}
.report-wrapper pre {
  font-family: "AnekLatin", "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  white-space: pre-wrap;
  word-wrap: break-word;
  overflow-wrap: break-word;
  margin: 0;
}
.report-wrapper .no-break {
  break-inside: avoid;
  -webkit-column-break-inside: avoid;
  page-break-inside: avoid;
  display: block;
}
.report-wrapper .badge {
  display: inline-block;
  color: white;
  font-weight: 500;
  border-radius: 0.2em;
  padding: 0.2em 0.4em;
}
.report-wrapper .badge.c-1 {
  background-color: #E63946;
}
.report-wrapper .badge.c-2 {
  background-color: #FB8500;
}
.report-wrapper .badge.c-3 {
  background-color: #2A9D8F;
}
.report-wrapper .badge.c-4 {
  background-color: #0077B6;
}
.report-wrapper .badge.c-5 {
  background-color: #8338EC;
}
.report-wrapper .badge.c-6 {
  background-color: #FF006E;
}
.report-wrapper .badge.c-7 {
  background-color: #00AFB9;
}
.report-wrapper .badge.c-8 {
  background-color: #F4A261;
}
.report-wrapper .badge.c-9 {
  background-color: #3A0CA3;
}
.report-wrapper .badge.c-10 {
  background-color: #006D77;
}
.report-wrapper .badge.c-11 {
  background-color: #C11277;
}
.report-wrapper .badge.c-12 {
  background-color: #00B4D8;
}
.report-wrapper .badge.c-13 {
  background-color: #2B2D42;
}
.report-wrapper .badge.c-14 {
  background-color: #70E000;
}
.report-wrapper .badge.c-15 {
  background-color: #D00000;
}
.report-wrapper .badge.c-16 {
  background-color: #5A189A;
}
